from flask import Flask, render_template, request, redirect, url_for, session
import os

app = Flask(__name__)
app.secret_key = 'your_secret_key_here'

DATA_DIR = 'data'


def load_news_data(filename):
    filepath = os.path.join(DATA_DIR, filename)
    news = []
    if os.path.isfile(filepath):
        with open(filepath, 'r', encoding='utf-8') as file:
            for line in file:
                parts = line.strip().split('||')
                if len(parts) >= 4:
                    # supporting optional extra fields
                    news.append({
                        'id': int(parts[0]),
                        'title': parts[1],
                        'content': parts[2],
                        'category': parts[3],
                        'date': parts[4] if len(parts) > 4 else ''
                    })
    return news


def load_comments():
    comment_file = os.path.join(DATA_DIR, 'comments.txt')
    comments = []
    if os.path.isfile(comment_file):
        with open(comment_file, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('||')
                if len(parts) == 3:
                    comments.append({
                        'news_id': int(parts[0]),
                        'user': parts[1],
                        'comment': parts[2]
                    })
    return comments


def get_news_by_id(news_list, news_id):
    for n in news_list:
        if n['id'] == news_id:
            return n
    return None


@app.route('/')
def index():
    news = load_news_data("news.txt")
    bookmarks = session.get('bookmarks', [])
    bookmarked_news = [get_news_by_id(news, bid) for bid in bookmarks]
    bookmarked_news = [bn for bn in bookmarked_news if bn]
    return render_template('index.html', news=news, bookmarks=bookmarked_news, trending=news)


@app.route('/trending')
def trending():
    trending_news = load_news_data("news.txt")
    try:
        trending_news.sort(key=lambda x: x.get('date', ''), reverse=True)
    except Exception:
        pass
    bookmarks = session.get('bookmarks', [])
    bookmarked_news = [get_news_by_id(trending_news, bid) for bid in bookmarks]
    bookmarked_news = [bn for bn in bookmarked_news if bn]
    return render_template('trending.html', trending=trending_news, bookmarks=bookmarked_news)


@app.route('/bookmark/<int:news_id>', methods=['POST'])
def bookmark(news_id):
    bookmarks = session.get('bookmarks', [])
    if news_id not in bookmarks:
        bookmarks.append(news_id)
    session['bookmarks'] = bookmarks
    return redirect(request.referrer or url_for('index'))


@app.route('/remove_bookmark/<int:news_id>', methods=['POST'])
def remove_bookmark(news_id):
    bookmarks = session.get('bookmarks', [])
    if news_id in bookmarks:
        bookmarks.remove(news_id)
    session['bookmarks'] = bookmarks
    return redirect(request.referrer or url_for('index'))


@app.route('/comments', methods=['GET', 'POST'])
def comments():
    news = load_news_data("news.txt")
    comments = load_comments()
    if request.method == 'POST':
        news_id = request.form.get('news_id', type=int)
        user = request.form.get('user', '').strip()
        comment_text = request.form.get('comment', '').strip()
        if news_id and user and comment_text:
            comment_line = f"{news_id}||{user}||{comment_text}\n"
            with open(os.path.join(DATA_DIR, 'comments.txt'), 'a', encoding='utf-8') as f:
                f.write(comment_line)
            comments = load_comments()
        return redirect(url_for('comments'))
    comments_by_news = {}
    for c in comments:
        comments_by_news.setdefault(c['news_id'], []).append(c)
    bookmarks = session.get('bookmarks', [])
    bookmarked_news = [get_news_by_id(news, bid) for bid in bookmarks]
    bookmarked_news = [bn for bn in bookmarked_news if bn]
    return render_template('comments.html', news=news, comments=comments_by_news, bookmarks=bookmarked_news)


if __name__ == '__main__':
    app.run(debug=True)

